/* bondScheduleMapper.getMspBondMstSeqNum */
SELECT  
		BOND_SEQ_NUM
FROM    
        MSP_BOND_MST
WHERE   
		1 = 1
		AND 	CONTRACT_NUM = #{contractNum}
		AND		CHRG_ITEM_CD = #{chrgItemCd}
		AND		MST_YN = 'Y'

mapper.update:
   		/** bondScheduleMapper.updateMspBondMst */
   		UPDATE MSP_BOND_MST
		SET 
			  MST_YN = 'N'

		WHERE 	1 = 1
				AND 	BOND_SEQ_NUM = #{bondSeqNum}

mapper.insert:
		/* bondScheduleMapper.insertMspBondMstSelectSeq */

		INSERT INTO MSP_BOND_MST (
			BOND_SEQ_NUM
			, CONTRACT_NUM
			, MST_YN
			, CHRG_ITEM_CD
			, OPEN_DT
			, TMNT_DT
			, INST_YN
			, INST_MNTH_CNT
			, INST_AMT
			, PAY_STRT_DT
			, PAY_END_DT
			, PRDT_ID
            , PRDT_SRL_NUM
			, HNDST_AMT
			, SUBSD_AMT
			, AGNCY_SUBSD_AMT
			, GRNT_INSR_MNGM_NO
			, SVC_CNTR_NO
			, REGST_ID
			, REGST_DTTM
			, RVISN_ID
			, RVISN_DTTM
		) VALUES (
			SQ_MSP_BOND_01.NEXTVAL
			, #{contractNum}
			, 'Y'
			, #{chrgItemCd}
			, #{openDt}
			, #{tmntDt}
			, #{instYn}
			, #{instMnthCnt}
			, #{instAmt}
			, #{payStrtDt}
			, #{payEndDt}
			, #{prdtId}
            , #{prdtSrlNum}
			, #{hndstAmt}
			, #{subsdAmt}
			, #{agncySubsdAmt}
			, #{grntInsrMngmNo}
			, #{svcCntrNo}
			, 'SYSTEM'
			, SYSDATE
			, 'SYSTEM'
			, SYSDATE
		)


			SELECT SQ_MSP_BOND_01.CURRVAL FROM DUAL

/* bondScheduleMapper.insertMspBondDtl */

INSERT INTO MSP_BOND_DTL (
	BOND_SEQ_NUM
	, CONTRACT_NUM
	, INST_MNTH_NUM
	, BILL_YM
	, BILL_AMT
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	#{bondSeqNum}
	, #{contractNum}
	, #{instMnthNum}
	, TO_CHAR(ADD_MONTHS(#{payStrtDt}, #{payNum}-1),'YYYYMM')
	, #{billAmt}
	, 'SYSTEM'
	, SYSDATE
	, 'SYSTEM'
	, SYSDATE
)

/* bondScheduleMapper.insertSelectMspGrntInsrInfo */
INSERT INTO MSP_GRNT_INSR_INFO ( GRNT_INSR_MNGM_NO , CONTRACT_NUM , APPL_END_DTTM , APPL_STRT_DTTM , PRDT_ID , PRDT_SRL_NUM , PRDT_AMT , OPEN_DT , INST_AMT , INST_CNT , INST_PAY_STRT_DT , INST_PAY_END_DT , GRNT_INSR_AMT , GRNT_INSR_STRT_DT , GRNT_INSR_END_DT , SVC_CNTR_NO , REGST_ID , REGST_DTTM , RVISN_ID , RVISN_DTTM )
SELECT A.GRNT_INSR_MNGM_NO , A.CONTRACT_NUM , '99991231235959' AS APPL_END_DTTM , B.EVNT_TRTM_DT AS APPL_STRT_DTTM , D.PRDT_ID AS PRDT_ID , D.PRDT_SRL_NUM AS PRDT_SRL_NUM , A.HNDST_AMT AS PRDT_AMT , A.OPEN_DT , A.INST_AMT , A.INST_MNTH_CNT AS INST_CNT , A.PAY_STRT_DT AS INST_PAY_STRT_DT , A.PAY_END_DT AS INST_PAY_END_DT , A.INST_AMT AS GRNT_INSR_AMT , SUBSTR(A.GRNT_INSR_MNGM_NO,0,8) AS GRNT_INSR_STRT_DT , TO_CHAR(ADD_MONTHS(TO_DATE(SUBSTR(A.GRNT_INSR_MNGM_NO,0,8), 'YYYYMMDD'), A.INST_MNTH_CNT-1), 'YYYYMMDD') AS GRNT_INSR_END_DT , A.SVC_CNTR_NO AS SVC_CNTR_NO , 'SYSTEM' AS REGST_ID , SYSDATE AS REGST_DTTM , 'SYSTEM' AS RVISN_ID , SYSDATE AS RVISN_DTTM FROM MSP_BOND_MST A , MSP_JUO_SUB_INFO B , MSP_JUO_ADD_INFO C , ( SELECT DISTINCT A.CONTRACT_NUM, A.MODEL_ID AS PRDT_ID, B.PRDT_SRL_NUM FROM MSP_JUO_MODEL_INFO A , LGS_PRDT_SRL_MST B WHERE A.CONTRACT_NUM = B.SVC_CT_NUM AND A.MODEL_ID = B.RPRS_PRDT_ID AND A.INTM_SRL_NO = B.PRDT_SRL_NUM AND A.APP_END_DATE = ( SELECT MAX(APP_END_DATE) FROM MSP_JUO_MODEL_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM AND MODEL_ID = A.MODEL_ID ) UNION ALL SELECT DISTINCT A.CONTRACT_NUM, A.MODEL_ID AS PRDT_ID, B.PRDT_SRL_NUM FROM MSP_JUO_MODEL_INFO A , LGS_OTCP_SRL_MST B WHERE A.CONTRACT_NUM = B.SVC_CT_NUM AND A.MODEL_ID = B.RPRS_PRDT_ID AND A.INTM_SRL_NO = B.PRDT_SRL_NUM AND A.APP_END_DATE = ( SELECT MAX(APP_END_DATE) FROM MSP_JUO_MODEL_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM AND MODEL_ID = A.MODEL_ID ) ) D WHERE 1=1 AND A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM AND A.CONTRACT_NUM = D.CONTRACT_NUM AND A.SVC_CNTR_NO = C.SVC_CNTR_NO AND C.APP_END_DATE LIKE '99991231%' AND A.CHRG_ITEM_CD = 'EQIST' AND A.MST_YN = 'Y' AND SUBSTR(A.OPEN_DT,0,6) <= TO_CHAR(ADD_MONTHS(SYSDATE, -1), 'YYYYMM') AND B.PPPO = 'PO' AND A.GRNT_INSR_MNGM_NO <> 'NONE' AND A.GRNT_INSR_MNGM_NO = UPPER(C.GRNT_INSR_MNGM_NO)

mapper.update:
   		/** bondChkScheduleMapper.updateMspGrntInsrInfo */
   		UPDATE 
   				MSP_GRNT_INSR_INFO
		SET 
				APPL_END_DTTM = #{applEndDttm}
				, NAME_CHG_DT = SUBSTR(#{nameChgDt}, 0, 8)
				, RVISN_ID = 'SYSTEM'
				, RVISN_DTTM = SYSDATE

		WHERE 	1 = 1
				AND 	GRNT_INSR_MNGM_NO = #{grntInsrMngmNo}
				AND 	CONTRACT_NUM = #{contractNum}
				AND 	APPL_END_DTTM = '99991231235959'

