		, INST_PAY_STRT_DT
		, INST_PAY_END_DT
		, GRNT_INSR_AMT
		, GRNT_INSR_STRT_DT
		, GRNT_INSR_END_DT
		, SVC_CNTR_NO
		, REGST_ID
		, REGST_DTTM
		, RVISN_ID
		, RVISN_DTTM
	) VALUES (
		#{grntInsrMngmNo}
		, #{contractNum}
		, '99991231235959'
		, #{nameChgDt}
		, #{prdtId}
		, #{prdtSrlNum}
		, #{prdtAmt}
		, #{openDt}
		, #{instAmt}
		, #{instCnt}
		, #{instPayStrtDt}
		, #{instPayEndDt}
		, #{grntInsrAmt}
		, #{grntInsrStrtDt}
		, #{grntInsrEndDt}
		, #{newSvcCntrNo}
		, 'SYSTEM'
		, SYSDATE
		, 'SYSTEM'
		, SYSDATE
	)
